export default function Footer() {
  return (
      <footer className="bg-[#FBFBFB] px-5 pb-12.5 pt-0 md:px-5 md:pb-10 lg:px-[30px] lg:pb-[100px]">
        <div className="mx-auto w-full max-w-[1100px]">
          <div className="flex flex-col items-center gap-12 border-b border-[#84B7CA] pb-0 pt-[100px] md:gap-10 lg:flex-row lg:items-start lg:justify-between lg:gap-17.5 lg:pb-8">
            <div className="w-[70px] shrink-0">
              <Link href="https://invest4kids.de/" className="block">
                <Image
                    src={invest4kidsLogo}
                    alt="Invest4Kids logo"
                    width={70}
                    height={44}
                    className="h-auto w-full"
                />
              </Link>
            </div>

            <div className="flex w-full flex-col items-center gap-12 md:gap-10 lg:flex-row lg:items-start lg:justify-start lg:gap-2">
              <section className="w-full md:max-w-[650px]">
                <h2 className="mb-3 pl-3 text-center font-poppins text-[16px] leading-6 font-bold text-text-medium md:text-[18px] md:leading-7 lg:text-left">
                  Navigation
                </h2>
                <nav>
                  <ul className="m-0 grid w-full grid-cols-4 p-0 md:grid-cols-6 lg:flex lg:w-auto lg:flex-wrap lg:justify-start ">
                    {navLinks.map(({ label, href, hasArrow, children, spanClass }) => (
                        <li
                            key={label}
                            className={`${spanClass ?? "col-span-1"} group/nav relative px-[17px] py-3 text-center lg:w-auto lg:px-3 lg:text-left`}
                        >
                          <Link
                              href={href}
                              className="inline-flex items-center gap-1 font-outfit text-[16px] leading-[21px] font-normal text-text-medium transition-colors hover:text-accent-hover md:text-[18px] md:leading-[24.5px]"
                          >
                            <span>{label}</span>
                            {hasArrow ? (
                                <ChevronDown className="h-4 w-4 transition-transform group-hover/nav:rotate-180" strokeWidth={1.8} />
                            ) : null}
                          </Link>
                          {children && (
                            <div className="invisible absolute top-full left-1/2 z-10 -translate-x-1/2 pt-2 opacity-0 transition-all group-hover/nav:visible group-hover/nav:opacity-100 lg:left-0 lg:translate-x-0">
                              <ul className="min-w-max rounded-lg bg-white py-2 shadow-[0_4px_20px_rgba(0,0,0,0.1)]">
                                {children.map((child) => (
                                  <li key={child.href}>
                                    <Link
                                      href={child.href}
                                      className="block px-5 py-2 font-outfit text-[13px] leading-[18px] font-normal text-text-medium transition-colors hover:text-accent-hover"
                                    >
                                      {child.label}
                                    </Link>
                                  </li>
                                ))}
                              </ul>
                            </div>
                          )}
                        </li>
                    ))}
                  </ul>
                </nav>
              </section>

              <section className="mb-[34px] mr-10 flex flex-col items-center lg:mb-0 lg:w-auto lg:shrink-0 lg:items-start">
                <h2 className="mb-6 text-center font-poppins text-[16px] leading-6 font-bold text-text-medium md:text-[18px] md:leading-7 lg:text-left">
                  Folge Uns
                </h2>
                <div className="flex items-center gap-[15px] lg:gap-4">
                  {socialLinks.map(({ href, label, viewBox, path }) => (
                      <Link
                          key={label}
                          href={href}
                          target="_blank"
                          rel="noopener noreferrer"
                          aria-label={label}
                          className="inline-flex h-8.5 w-8.5 items-center justify-center rounded-full bg-[#CDCDCD4D] text-text-medium transition-colors hover:bg-accent-hover"
                      >
                        <svg
                            aria-hidden="true"
                            viewBox={viewBox}
                            className="h-5 w-5 fill-current"
                            xmlns="http://www.w3.org/2000/svg"
                        >
                          <path d={path} />
                        </svg>
                      </Link>
                  ))}
                </div>
              </section>
            </div>
          </div>

          <div className="pt-10 lg:pt-[50px]">
            <p className="pb-[100px] text-center font-outfit text-lg leading-[21px] font-normal text-secondary lg:pb-0">
              © {new Date().getFullYear()} Invest4Kids. Alle Rechte vorbehalten.
            </p>
          </div>
        </div>
      </footer>
  );
}
